import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    // Shared event table: [100,DEPOSIT,500], [200,WITHDRAW,100], [300,DEPOSIT,50]
    private static final String[][] EVENTS = {
            {"100", "DEPOSIT",  "500"},
            {"200", "WITHDRAW", "100"},
            {"300", "DEPOSIT",  "50"}
    };

    @Test
    void queryAtExactTimestamp() {
        // Timestamp 200 is inclusive: events at 100 and 200 apply -> 0+500-100 = 400
        assertEquals(400L,
                new Solution().balanceAtTimestamp(EVENTS, 200L));
    }

    @Test
    void queryBeforeAllEvents() {
        // queryTimestamp=99 -> no events qualify -> balance 0
        assertEquals(0L,
                new Solution().balanceAtTimestamp(EVENTS, 99L));
    }

    @Test
    void queryAfterAllEvents() {
        // queryTimestamp=999 -> all three events apply -> 500-100+50 = 450
        assertEquals(450L,
                new Solution().balanceAtTimestamp(EVENTS, 999L));
    }

    @Test
    void emptyEvents() {
        assertEquals(0L,
                new Solution().balanceAtTimestamp(new String[][]{}, 5000L));
    }

    @Test
    void orderMatters() {
        // queryTimestamp=100 applies only the first event (DEPOSIT 500) -> 500
        // queryTimestamp=200 applies first two (DEPOSIT 500, WITHDRAW 100) -> 400
        // Verifies the cut-off boundary is respected chronologically.
        assertEquals(500L,
                new Solution().balanceAtTimestamp(EVENTS, 100L));
        assertEquals(400L,
                new Solution().balanceAtTimestamp(EVENTS, 200L));
    }

    @Test
    void queryBetweenTimestamps() {
        // queryTimestamp=150 — between 100 and 200 — only first event applies -> 500
        assertEquals(500L,
                new Solution().balanceAtTimestamp(EVENTS, 150L));
    }

    @Test
    void withdrawBelowZeroWithinWindow() {
        // Events: [10, DEPOSIT, 100], [20, WITHDRAW, 300] -> balance at ts=20 = -200
        String[][] ev = {
                {"10", "DEPOSIT",  "100"},
                {"20", "WITHDRAW", "300"}
        };
        assertEquals(-200L,
                new Solution().balanceAtTimestamp(ev, 20L));
    }
}
